interceptor.preaction:

Util u=new Util();
String ip=u.getRemoteIP(rrequest);
rrequest.getRequest().setAttribute("reqKey2", ip);
String riqi=u.getDate();
rrequest.getRequest().setAttribute("reqKey3", riqi);


Date d=new Date();
String beginTime=rrequest.getStringAttribute("TXN_DT","");
String org_id=rrequest.getStringAttribute("ORG_ID1","");
System.out.println("beginTime:"+beginTime+"org_id:"+org_id);

if(beginTime.equals(""))
{
	SimpleDateFormat dateformat = new SimpleDateFormat("yyyy-MM-dd");
	beginTime=dateformat.format(new Date(d.getTime()-7*24*60*60*1000));
	rrequest.setAttribute("TXN_DT",beginTime);
}

String endTime=rrequest.getStringAttribute("TXN_DT_END","");
if(endTime.equals(""))
{
	SimpleDateFormat dateformat = new SimpleDateFormat("yyyy-MM-dd");
	endTime=dateformat.format(new Date(d.getTime()-1*24*60*60*1000));
	rrequest.setAttribute("TXN_DT_END",endTime);
}

interceptor.beforedisplay-perrow:

if(rowDataBean.getReportTypeObj().getLstReportData()!=null&&rowDataBean.getRowindex()>=0&&rowDataBean.getRowindex()<rowDataBean.getReportTypeObj().getLstReportData().size())
{
	String  zhuangtai=String.valueOf(rowDataBean.getColData("BONUS_STATUS_ID"));

	System.out.println("状态ID"+zhuangtai);
	System.out.println(zhuangtai=="0");
	if(zhuangtai.equals("0"))
	{

		rowDataBean.setColData("SUM","0");//如果未计提，则奖励金额为0
	}else{

		String per1=String.valueOf(rowDataBean.getColData("RECOMMEND_PEOPLE"));
		String per2=String.valueOf(rowDataBean.getColData("SALES_PEOPLE"));

		System.out.println("推荐人和销售人的员工号"+per1+per2);
		String reBonus=String.valueOf(rowDataBean.getColData("RECOMMEND_BONUS"));
		String saBonus=String.valueOf(rowDataBean.getColData("SALES_BONUS"));

		String reRatio=String.valueOf(rowDataBean.getColData("RECOMMEND_RATIO"));
		String saRatio=String.valueOf(rowDataBean.getColData("SALES_RATIO"));

		double reB=0;
		double saB=0;
		double reBra=0;
		double saBra=0;
		double rebSum=0;
		double sabSum=0;
		double sum =0;
		HttpSession session = rrequest.getRequest().getSession();
		String user_id = (String) session.getAttribute("user_id");
		System.out.println("员工号"+user_id);
		if(user_id.equals(per1))
		{    System.out.println("start=======per1"+"reBonus="+reBonus+";"+"reRatio="+reRatio);
			if(reBonus!=null&&!reBonus.equals(""))
			{
				reB=Double.parseDouble(reBonus);
			}
			else
			{
				reB=0.00;
			}
			if(reRatio!=null&&!reRatio.equals("")&&!reRatio.equals("null"))
			{
				System.out.println("reRatio不为空");
				reBra=Double.parseDouble(reRatio);
			}
			else
			{
				reBra=0.00;
			}
			System.out.println("end===========per1"+"reBonus="+reBonus+";"+"reRatio="+reRatio);

		}
		if(user_id.equals(per2)){
			System.out.println("start===per2"+"reBonus="+reBonus+";"+"reRatio="+reRatio);
			if(saBonus!=null&&!saBonus.equals(""))
			{
				saB=Double.parseDouble(saBonus);
			}
			else
			{
				saB=0.00;
			}
			if(saRatio!=null&&!saRatio.equals("")&&!saRatio.equals("null"))
			{
				saBra=Double.parseDouble(saRatio);
			}
			else
			{
				saBra=0.00;
			}
			System.out.println("per2"+"reBonus="+reBonus+";"+"reRatio="+reRatio);

		}
		System.out.println(reB +";"+ saB);

		sum=reB+saB;


		rowDataBean.setColData("SUM",sum+"");//转为string才行
	}
}

